sql:
SELECT num_ratings, average_rating 
FROM album_ratings 
WHERE album_id = 0;

SELECT average_rating
FROM user_album_ratings
WHERE user_id = 1;

SELECT num_albums_rated, average_rating
FROM user_album_ratings
WHERE num_albums_rated > 1000;

SELECT COUNT(rating) AS total_ratings
FROM rating_history
WHERE rating IS NOT NULL;

external_knowledge:
; Verified users refer to users with 'is_verified' set to 1 in the users table; 
; Top-rated albums are those with the highest ratings given by verified users;
; The maximum rating given by a user for an album determines the album's rank.

- 'top 10' implies ranking based on average ratings from highest to lowest; 
- 'genres' refers to the broad categories of music such as Pop, Rock, Jazz, etc; 
- 'deleted albums' refers to those albums with 'is_deleted' = 1; 
- 'updated ratings' refers to those ratings with 'is_updated' = 1;
- The rating is the average of individual album ratings;
- Rating is on a scale from 1-100.

sql:
SELECT AVG(rating) AS avg_user_rating
FROM ratings
WHERE user_id > 0;
